function minDays(power) {
    const n = power.length;
    const ans = 1e9;
    const dp = new Array(1 << n).fill(1e9);

    dp[0] = 0;
    const sortedPower = [...power].sort((a, b) => a - b);

    for (let i = 0; i < (1 << n); ++i) {
        let powerSum = 0;
        for (let j = 0; j < n; ++j) {
            if (i & (1 << j)) {
                powerSum += sortedPower[j];
            }
        }
        const gain = 1 + countBits(i);
        for (let j = 0; j < n; ++j) {
            if (!(i & (1 << j)) && gain > sortedPower[j]) {
                dp[i | (1 << j)] = Math.min(dp[i | (1 << j)], dp[i] + 1);
            }
        }
    }
    return dp[(1 << n) - 1];

    function countBits(num) {
        let count = 0;
        while (num) {
            num &= (num - 1);
            ++count;
        }
        return count;
    }
}
```

    1. Sort the given `power` array in ascending order.
2. We will use dynamic programming. Create a `dp` array sized `2^n` and initialized with a large number (eg., `1e9`), where `n` is the length of the `power` array. `dp[i]` represents the minimum number of days needed to defeat the monsters represented by the bitmask `i`.
3. Set `dp[0] = 0`, because no days are needed if there are no monsters.
4. Loop through all possible subsets of the sorted `power` array by iterating through `1 << n`.
5. Calculate the mana points gain as `1 + number of bits set in i`.
6. Iterate through each of the monsters (0 to n-1), if the monster is not already defeated as indicated by the bitmask (`!(i & (1 << j))`), and if the mana is greater than the power of the monster (`gain > sorted_power[j]`), we find the minimum of the current `dp` value at `i | (1 << j)` and `dp[i] + 1`, and store the result back in `dp[i | (1 << j)]`.
7. After iterating through all possible subsets, return the value of `dp[(1 << n) - 1]`, which is the minimum number of days needed to defeat all the monsters.

